@import "tailwindcss";

html, body {
  overscroll-behavior-y: contain;
  overflow: hidden;
}

.hide-scroll::-webkit-scrollbar {
  display: none;
}
.hide-scroll {
  -ms-overflow-style: none;
  scrollbar-width: none;
}

